import React from 'react';

export type InputProps = {
  id: string;
  type?: 'text' | 'number' | 'password' | 'tel' | 'email' | 'date';
  name: string;
  placeholder: string;
  value?: string | number;
  onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
  className?: string;
  full?: boolean;
  readOnly?: boolean;
  required?: boolean;
};

const Input: React.FC<InputProps> = ({
  id,
  type = 'text',
  name,
  placeholder,
  value = '',
  onChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    return;
  },
  className,
  full = false,
  readOnly = false,
  required = false
}: InputProps) => {
  const width = full ? 'w-full' : '';
  return (
    <input
      type={type}
      id={id}
      name={name}
      placeholder={placeholder}
      value={value}
      onChange={onChange}
      className={`${width} px-3 py-2 rounded border border-solid box-border border-gray-300 ${className}`}
      required={required}
      readOnly={readOnly}
      disabled={readOnly}
    />
  );
};

Input.displayName = 'Input';
Input.defaultProps = {
  type: 'text',
  value: '',
  onChange: () => {
    return;
  },
  className: '',
  readOnly: false,
  required: false
};

export default Input;
