import { Link } from 'gatsby';
import React from 'react';
import { FaBullhorn, FaEnvelope, FaTimes } from 'react-icons/fa';
import uuid from '../../../utils/uuid';
import Container from '../../atoms/Container';
import Banner from '../../molecules/Banner';

export type Section = {
  id: string;
  icon: any;
};

export type MenuProps = { fixed?: boolean; sections?: Array<Section> };

const Menu: React.FC<MenuProps> = ({ fixed = false, sections = [] }) => {
  const scrollTo = (id: string) => {
    const top: number = document.getElementById(id)?.offsetTop || 0;
    window.scrollTo({ top: top - 120, behavior: 'smooth' });
  };

  const fixedTop: string = fixed ? 'fixed z-10 top-0' : '';
  return (
    <nav className={`${fixedTop} bg-white w-full border-b`}>
      <Banner>
        <div className="flex items-center justify-between">
          <div className="flex items-center">
            <FaBullhorn className="mr-2" />
            <span>
              This is my{' '}
              <a
                href="https://bradfrost.com/blog/post/atomic-web-design/"
                target="_blank"
                rel="noreferrer"
                className="underline uppercase"
              >
                atomic design
              </a>{' '}
              masterpiece
            </span>
          </div>
          <div>
            <FaTimes />
          </div>
        </div>
      </Banner>
      <Container>
        <div className="flex items-center py-4">
          <Link to="/">
            <div className="text-2xl cursor-pointer">HD</div>
          </Link>
          <div className="ml-8 mr-auto flex items-center gap-8">
            <Link to="/contact">
              <div className="flex items-center gap-2">
                <FaEnvelope />
                <span>Contact</span>
              </div>
            </Link>
          </div>
          <div className="ml-auto flex items-center gap-8">
            {sections.map(({ id, icon }) => {
              return (
                <button
                  key={uuid()}
                  onClick={() => scrollTo(id)}
                  className="uppercase"
                >
                  <div className="flex items-center gap-2">
                    {icon}
                    <span>{id}</span>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </Container>
    </nav>
  );
};

export default Menu;
